461	// ─── Quicksort ────────────────────────────────────────────────────────────────
462	
463	/// C: `l_randomizePivot()` — produce a "random" `u32` to randomize pivot
464	/// selection when a partition is severely imbalanced.
465	///
466	/// C: uses `clock()` and `time()` as entropy sources via `memcpy` into a
467	/// `unsigned int` array whose elements are summed.
468	///
469	/// PORT NOTE: Rust uses `SystemTime` as an entropy source instead of
470	/// POSIX `clock()`/`time()`. The mixing is simplified (subsecond nanos XOR-
471	/// shifted) but serves the same purpose: breaking pathological patterns.
472	fn randomize_pivot() -> u32 {
473	    use std::time::{SystemTime, UNIX_EPOCH};
474	    let nanos = SystemTime::now()
475	        .duration_since(UNIX_EPOCH)
476	        .map(|d| d.subsec_nanos())
477	        .unwrap_or(0u32);
478	    nanos ^ nanos.wrapping_shr(16)
479	}
480	
481	/// C: `set2(L, i, j)` — pop the top two stack values and assign them to
482	/// `table[i]` and `table[j]` respectively (table is at stack position 1).
483	///
484	/// ```c
485	/// static void set2 (lua_State *L, IdxT i, IdxT j) {
486	///   lua_seti(L, 1, i);
487	///   lua_seti(L, 1, j);
488	/// }
489	/// ```
490	fn set2(state: &mut LuaState, i: IdxT, j: IdxT) -> Result<(), LuaError> {
491	    // First seti pops the stack top; second seti pops the new top.
492	    state.table_set_i(1, i as i64)?;
493	    state.table_set_i(1, j as i64)?;
494	    Ok(())
495	}
496	
497	/// C: `sort_comp(L, a, b)` — return `true` iff `stack[a] < stack[b]` per the
498	/// sort order: either the `<` operator (if arg 2 is nil) or the user's
499	/// comparison function at stack position 2.
500	///
501	/// ```c
502	/// static int sort_comp (lua_State *L, int a, int b) {
503	///   if (lua_isnil(L, 2))
504	///     return lua_compare(L, a, b, LUA_OPLT);
505	///   else {
506	///     int res;
507	///     lua_pushvalue(L, 2);
508	///     lua_pushvalue(L, a-1);
509	///     lua_pushvalue(L, b-2);
510	///     lua_call(L, 2, 1);
511	///     res = lua_toboolean(L, -1);
512	///     lua_pop(L, 1);
513	///     return res;
514	///   }
515	/// }
516	/// ```
517	///
518	/// The offsets `a-1` and `b-2` compensate for the function and first-argument
519	/// copies pushed before the respective values: `a-1` accounts for the function
520	/// push; `b-2` accounts for both the function push and the copy of `a`.
521	fn sort_comp(state: &mut LuaState, a: i32, b: i32) -> Result<bool, LuaError> {
522	    if state.type_at(2) == LuaType::Nil {
523	        // No user comparator: use the default `<` operator.
524	        return state.compare(a, b, CompareOp::Lt);
525	    }
526	    // User comparator at stack position 2.
527	    state.push_value_at(2);       // push function
528	    state.push_value_at(a - 1);   // push copy of a (compensate for function push)
529	    state.push_value_at(b - 2);   // push copy of b (compensate for function + a copy)
530	    // C: lua_call(L, 2, 1)
531	    state.call(2, 1)?;
532	    // C: res = lua_toboolean(L, -1); lua_pop(L, 1)
533	    // TODO(port): state.to_boolean(-1) → lua_toboolean (never fails); verify method name
534	    let res = state.to_boolean(-1);
535	    state.pop_n(1);
536	    Ok(res)
537	}
538	
539	/// C: `partition(L, lo, up)` — in-place partition around the pivot `P` that
540	/// is already on the top of the Lua stack.
541	///
542	/// Precondition: `a[lo] <= P == a[up-1] <= a[up]` and `P` is at stack top.
543	/// Postcondition: `a[lo..i-1] <= a[i] == P <= a[i+1..up]`; stack is clean.
544	/// Returns the final pivot index `i`.
545	///
546	/// ```c
547	/// static IdxT partition (lua_State *L, IdxT lo, IdxT up) {
548	///   IdxT i = lo;
549	///   IdxT j = up - 1;
550	///   for (;;) {
551	///     while ((void)lua_geti(L, 1, ++i), sort_comp(L, -1, -2)) {
552	///       if (l_unlikely(i == up - 1))
553	///         luaL_error(L, "invalid order function for sorting");
554	///       lua_pop(L, 1);
555	///     }
556	///     while ((void)lua_geti(L, 1, --j), sort_comp(L, -3, -1)) {
557	///       if (l_unlikely(j < i))
558	///         luaL_error(L, "invalid order function for sorting");
559	///       lua_pop(L, 1);
560	///     }
561	///     if (j < i) {
562	///       lua_pop(L, 1);
563	///       set2(L, up - 1, i);
564	///       return i;
565	///     }
566	///     set2(L, i, j);
567	///   }
568	/// }
569	/// ```
570	fn partition(state: &mut LuaState, lo: IdxT, up: IdxT) -> Result<IdxT, LuaError> {
571	    let mut i: IdxT = lo;
572	    let mut j: IdxT = up - 1;
573	    // Entry: stack top is P (pivot value).
574	    loop {
575	        // Advance i: find first a[i] >= P.
576	        // Stack during i-loop body: P(-2), a[i](-1)
577	        loop {
578	            i += 1;
579	            state.table_get_i(1, i as i64)?; // push a[i]
580	            if !sort_comp(state, -1, -2)? {
581	                // a[i] >= P: leave a[i] on stack and exit
582	                break;
583	            }
584	            // a[i] < P; check for invalid comparator
585	            if i == up - 1 {
586	                return Err(LuaError::runtime(format_args!(
587	                    "invalid order function for sorting"
588	                )));
589	            }
590	            state.pop_n(1); // remove a[i]
591	        }
592	        // Retreat j: find last a[j] <= P.
593	        // Stack during j-loop body: P(-3), a[i](-2), a[j](-1)
594	        loop {
595	            // PERF(port): wrapping_sub mirrors C unsigned IdxT behaviour for edge cases
596	            j = j.wrapping_sub(1);
597	            state.table_get_i(1, j as i64)?; // push a[j]
598	            if !sort_comp(state, -3, -1)? {
599	                // P >= a[j]: leave a[j] on stack and exit
600	                break;
601	            }
602	            // P < a[j]; check for invalid comparator
603	            if j < i {
604	                return Err(LuaError::runtime(format_args!(
605	                    "invalid order function for sorting"
606	                )));
607	            }
608	            state.pop_n(1); // remove a[j]
609	        }
610	        // Stack: P(-3), a[i](-2), a[j](-1)
611	        if j < i {
612	            // No out-of-place elements; finalize: place pivot at position i.
613	            state.pop_n(1); // pop a[j]; stack: P(-2), a[i](-1)
614	            set2(state, up - 1, i)?; // table[up-1] = a[i], table[i] = P; stack clean
615	            return Ok(i);
616	        }
617	        // Swap a[i] and a[j] to restore loop invariant.
618	        // set2: table[i] = a[j] (pops -1), table[j] = a[i] (pops new -1); stack: P(-1)
619	        set2(state, i, j)?;
620	    }
621	}
622	
623	/// C: `choosePivot(lo, up, rnd)` — select a pivot index in the middle half of
624	/// `[lo, up]`, randomised by `rnd`.
625	///
626	/// ```c
627	/// static IdxT choosePivot (IdxT lo, IdxT up, unsigned int rnd) {
628	///   IdxT r4 = (up - lo) / 4;
629	///   IdxT p = rnd % (r4 * 2) + (lo + r4);
630	///   lua_assert(lo + r4 <= p && p <= up - r4);
631	///   return p;
632	/// }
633	/// ```
634	fn choose_pivot(lo: IdxT, up: IdxT, rnd: u32) -> IdxT {
635	    let r4 = (up - lo) / 4; // range / 4
636	    let p = rnd % (r4 * 2) + (lo + r4);
637	    debug_assert!(lo + r4 <= p && p <= up - r4);
638	    p
639	}
640	
641	/// C: `auxsort(L, lo, up, rnd)` — recursive quicksort driver.
642	///
643	/// Sorts `table[lo..=up]` in place, recursing on the smaller partition and
644	/// tail-looping on the larger (to bound Rust's call stack). Randomises pivot
645	/// selection when a partition is badly imbalanced.
646	///
647	/// ```c
648	/// static void auxsort (lua_State *L, IdxT lo, IdxT up, unsigned int rnd) {
649	///   while (lo < up) {
650	///     IdxT p, n;
651	///     lua_geti(L, 1, lo); lua_geti(L, 1, up);
652	///     if (sort_comp(L, -1, -2)) set2(L, lo, up); else lua_pop(L, 2);
653	///     if (up - lo == 1) return;
654	///     if (up - lo < RANLIMIT || rnd == 0) p = (lo + up)/2;
655	///     else p = choosePivot(lo, up, rnd);
656	///     lua_geti(L, 1, p); lua_geti(L, 1, lo);
657	///     if (sort_comp(L, -2, -1)) set2(L, p, lo);
658	///     else {
659	///       lua_pop(L, 1); lua_geti(L, 1, up);
660	///       if (sort_comp(L, -1, -2)) set2(L, p, up); else lua_pop(L, 2);
661	///     }
662	///     if (up - lo == 2) return;
663	///     lua_geti(L, 1, p); lua_pushvalue(L, -1); lua_geti(L, 1, up - 1);
664	///     set2(L, p, up - 1);
665	///     p = partition(L, lo, up);
666	///     if (p - lo < up - p) {
667	///       auxsort(L, lo, p - 1, rnd); n = p - lo; lo = p + 1;
668	///     } else {
669	///       auxsort(L, p + 1, up, rnd); n = up - p; up = p - 1;
670	///     }
671	///     if ((up - lo) / 128 > n) rnd = l_randomizePivot();
672	///   }
673	/// }
674	/// ```
675	fn aux_sort(state: &mut LuaState, mut lo: IdxT, mut up: IdxT, mut rnd: u32) -> Result<(), LuaError> {
676	    while lo < up {
677	        // Step 1: ensure a[lo] <= a[up] (cheap two-element sort)
678	        state.table_get_i(1, lo as i64)?; // push a[lo]
679	        state.table_get_i(1, up as i64)?; // push a[up]
680	        // C: if (sort_comp(L, -1, -2)) — a[up] < a[lo]?
681	        if sort_comp(state, -1, -2)? {
682	            set2(state, lo, up)?; // swap so a[lo] <= a[up]
683	        } else {
684	            state.pop_n(2);
685	        }
686	        if up - lo == 1 {
687	            return Ok(()); // only 2 elements, now sorted
688	        }
689	
690	        // Step 2: choose pivot index
691	        let mut p: IdxT = if up - lo < RANLIMIT || rnd == 0 {
692	            (lo + up) / 2 // midpoint pivot for small/non-random runs
693	        } else {
694	            choose_pivot(lo, up, rnd)
695	        };
696	
697	        // Step 3: median-of-three: sort a[lo], a[p], a[up]
698	        state.table_get_i(1, p as i64)?;  // push a[p]
699	        state.table_get_i(1, lo as i64)?; // push a[lo]
700	        // C: if (sort_comp(L, -2, -1)) — a[p] < a[lo]?
701	        if sort_comp(state, -2, -1)? {
702	            set2(state, p, lo)?; // swap a[p] ↔ a[lo]; stack clean
703	        } else {
704	            state.pop_n(1); // remove a[lo]; stack: a[p]
705	            state.table_get_i(1, up as i64)?; // push a[up]; stack: a[p], a[up]
706	            // C: if (sort_comp(L, -1, -2)) — a[up] < a[p]?
707	            if sort_comp(state, -1, -2)? {
708	                set2(state, p, up)?; // swap a[p] ↔ a[up]; stack clean
709	            } else {
710	                state.pop_n(2); // remove a[up] and a[p]; stack clean
711	            }
712	        }
713	        // Stack is clean at this point.
714	        if up - lo == 2 {
715	            return Ok(()); // only 3 elements, now sorted
716	        }
717	
718	        // Step 4: move pivot to a[up-1] and call partition.
719	        //
720	        // Stack evolution:
721	        //   table_get_i(p):    a[p]  (-1)
722	        //   push_value_at(-1): a[p]  (-2), a[p]_copy  (-1)
723	        //   table_get_i(up-1): a[p]  (-3), a[p]_copy  (-2), a[up-1]  (-1)
724	        //   set2(p, up-1):     table[p] = a[up-1], table[up-1] = a[p]_copy;
725	        //                      stack: a[p] (-1)  ← pivot for partition
726	        state.table_get_i(1, p as i64)?;
727	        state.push_value_at(-1); // duplicate: two copies of pivot on stack
728	        state.table_get_i(1, (up - 1) as i64)?;
729	        set2(state, p, up - 1)?;
730	        // One copy of the pivot value remains at the stack top for partition.
731	
732	        p = partition(state, lo, up)?;
733	        // Stack is clean after partition returns.
734	
735	        // Step 5: recurse on smaller partition; tail-loop on larger.
736	        let n: IdxT;
737	        if p - lo < up - p {
738	            aux_sort(state, lo, p - 1, rnd)?;
739	            n = p - lo;
740	            lo = p + 1; // tail: sort [p+1 .. up]
741	        } else {
742	            aux_sort(state, p + 1, up, rnd)?;
743	            n = up - p;
744	            up = p - 1; // tail: sort [lo .. p-1]
745	        }
746	
747	        // Re-randomise if the partition was severely imbalanced.
748	        // C: if ((up - lo) / 128 > n) rnd = l_randomizePivot()
749	        if (up - lo) / 128 > n {
750	            rnd = randomize_pivot();
751	        }
752	    }
753	    Ok(())
754	}
755	
756	/// C: `sort(L)` — implements `table.sort(t [, comp])`.
757	///
758	/// ```c
759	/// static int sort (lua_State *L) {
760	///   lua_Integer n = aux_getn(L, 1, TAB_RW);
761	///   if (n > 1) {
762	///     luaL_argcheck(L, n < INT_MAX, 1, "array too big");
763	///     if (!lua_isnoneornil(L, 2))
764	///       luaL_checktype(L, 2, LUA_TFUNCTION);
765	///     lua_settop(L, 2);
766	///     auxsort(L, 1, (IdxT)n, 0);
767	///   }
768	///   return 0;
769	/// }
770	/// ```
771	pub fn sort(state: &mut LuaState) -> Result<usize, LuaError> {
772	    let n = aux_getn(state, 1, TAB_RW)?;
773	    if n > 1 {
774	        if !(n < i32::MAX as i64) {
775	            return Err(LuaError::arg_error(1, "array too big"));
776	        }
777	        if !matches!(state.type_at(2), LuaType::None | LuaType::Nil) {
778	            state.check_arg_type(2, LuaType::Function)?;
779	        }
780	        // C: lua_settop(L, 2) — discard any extra arguments.
781	        // Must go through the public C-API set_top (relative to the call
782	        // frame); the inherent LuaState::set_top treats its argument as
783	        // an absolute stack slot and would corrupt the frame.
784	        lua_vm::api::set_top(state, 2)?;
785	        aux_sort(state, 1, n as IdxT, 0)?;
786	    }
787	    Ok(0)
788	}
789	
790	// ─── Registration ─────────────────────────────────────────────────────────────
791	
792	/// C: `tab_funcs[]` — the function registration table for `require("table")`.
793	///
794	/// ```c
795	/// static const luaL_Reg tab_funcs[] = {
796	///   {"concat", tconcat}, {"insert", tinsert}, {"pack", tpack},
797	///   {"unpack", tunpack}, {"remove", tremove}, {"move", tmove},
798	///   {"sort", sort}, {NULL, NULL}
799	/// };
800	/// ```
801	///
802	/// PORT NOTE: In Rust we represent this as a slice of `(&[u8], fn-ptr)` pairs;
803	/// the sentinel `{NULL, NULL}` is implicit (the slice has a known length).
804	pub const TABLE_FUNCS: &[(&[u8], fn(&mut LuaState) -> Result<usize, LuaError>)] = &[
805	    (b"concat", concat),
806	    (b"insert", insert),
807	    (b"pack", pack),
808	    (b"unpack", unpack),
809	    (b"remove", remove),
810	    (b"move", tmove),
811	    (b"sort", sort),
812	];
813	
814	// ─── Module opener ────────────────────────────────────────────────────────────
815	
816	/// C: `luaopen_table(L)` — open the `table` library.
817	///
818	/// ```c
819	/// LUAMOD_API int luaopen_table (lua_State *L) {
820	///   luaL_newlib(L, tab_funcs);
821	///   return 1;
822	/// }
823	/// ```
824	pub fn open_table(state: &mut LuaState) -> Result<usize, LuaError> {
825	    // C: LUAMOD_API → pub  (see macros.tsv)
826	    // TODO(port): state.new_lib → luaL_newlib; creates a new table and registers functions;
827	    //             verify method name and signature
828	    state.new_lib(TABLE_FUNCS)?;
829	    Ok(1)
830	}
831	
832	// ──────────────────────────────────────────────────────────────────────────────
833	// PORT STATUS
834	//   source:        src/ltablib.c  (430 lines, 14 functions)
835	//   target_crate:  lua-stdlib
836	//   confidence:    medium
837	//   todos:         18
838	//   port_notes:    5
839	//   unsafe_blocks: 0
840	//   notes:         Logic is faithfully translated. All TODOs are method-name
841	//                  uncertainties for LuaState API calls (table_get_i, table_set_i,
842	//                  opt_arg_integer, opt_arg_lstring, get_metatable, to_bytes_at,
843	//                  push_lstring, push_value_at, compare, new_lib, set_top,
844	//                  check_stack_growth, type_name_str_at, create_table) — Phase B
845	//                  maps these to the real method names once lua-vm is drafted.
846	//                  Stack cleanup on error paths is elided (C uses longjmp);
847	//                  needs Phase B attention in check_tab and add_field.
848	// ──────────────────────────────────────────────────────────────────────────────
849

